#!/usr/bin/env bash
# tests/helpers.sh — shared setup/teardown for CLI tests

setup_test_dir() {
  TEST_DIR="$(mktemp -d)"
  export TEST_DIR
  # Point CLI at the test directory
  cd "$TEST_DIR"
}

teardown_test_dir() {
  cd /
  [[ -n "${TEST_DIR:-}" ]] && rm -rf "$TEST_DIR"
}

# Path to the CLI
CLI_BIN="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)/bin/founder-os.js"
export CLI_BIN

assert_file_exists() {
